283→/* ------------------------------------------------------------------ */
284→/*  Extracted CSV upload fields (reused in tabs and standalone modes)   */
285→/* ------------------------------------------------------------------ */
286→
287→interface CsvUploadFieldsProps {
288→  productName: string;
289→  setProductName: (v: string) => void;
290→  csvText: string;
291→  setCsvText: (v: string) => void;
292→  pastedCsv: string;
293→  setPastedCsv: (v: string) => void;
294→  fileName: string;
295→  setFileName: (v: string) => void;
296→  fileInputRef: React.RefObject<HTMLInputElement | null>;
297→  handleFileUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
298→  handleCsvSubmit: () => void;
299→  loading: boolean;
300→}
301→
302→function CsvUploadFields({
303→  productName,
304→  setProductName,
305→  csvText,
306→  setCsvText,
307→  pastedCsv,
308→  setPastedCsv,
309→  fileName,
310→  setFileName,
311→  fileInputRef,
312→  handleFileUpload,
313→  handleCsvSubmit,
314→  loading,
315→}: CsvUploadFieldsProps) {
316→  const [isDragging, setIsDragging] = useState(false);
317→  const dragCounter = useRef(0);
318→
319→  const handleDragEnter = useCallback((e: React.DragEvent) => {
320→    e.preventDefault();
321→    e.stopPropagation();
322→    dragCounter.current++;
323→    if (e.dataTransfer.items?.length) setIsDragging(true);
324→  }, []);
325→
326→  const handleDragLeave = useCallback((e: React.DragEvent) => {
327→    e.preventDefault();
328→    e.stopPropagation();
329→    dragCounter.current--;
330→    if (dragCounter.current === 0) setIsDragging(false);
331→  }, []);
332→
333→  const handleDragOver = useCallback((e: React.DragEvent) => {
334→    e.preventDefault();
335→    e.stopPropagation();
336→  }, []);
337→
338→  const handleDrop = useCallback((e: React.DragEvent) => {
339→    e.preventDefault();
340→    e.stopPropagation();
341→    setIsDragging(false);
342→    dragCounter.current = 0;
343→
344→    const file = e.dataTransfer.files?.[0];
345→    if (!file) return;
346→
347→    const ext = file.name.split(".").pop()?.toLowerCase();
348→    if (ext !== "csv" && ext !== "txt") return;
349→
350→    setFileName(file.name);
351→    setPastedCsv("");
352→    const reader = new FileReader();
353→    reader.onload = (event) => {
354→      setCsvText(event.target?.result as string);
355→    };
356→    reader.readAsText(file);
357→  }, [setCsvText, setFileName, setPastedCsv]);
358→
359→  return (
360→    <>
361→      <div>
362→        <label className="text-xs font-medium text-white/50 mb-1.5 block uppercase tracking-wider">
363→          Product / Business Name
364→        </label>
365→        <Input
366→          placeholder="e.g., Apple AirPods Pro (2nd Gen)"
367→          value={productName}
368→          onChange={(e) => setProductName(e.target.value)}
369→          disabled={loading}
370→          className="bg-white/5 border-white/10 text-white placeholder:text-white/20 focus:border-violet-500/50 focus:ring-violet-500/20"
371→        />
372→      </div>
373→
374→      <div>
375→        <label className="text-xs font-medium text-white/50 mb-1.5 block uppercase tracking-wider">
376→          Upload CSV File
377→        </label>
378→        <div
379→          onClick={() => fileInputRef.current?.click()}
380→          onDragEnter={handleDragEnter}
381→          onDragLeave={handleDragLeave}
382→          onDragOver={handleDragOver}
383→          onDrop={handleDrop}
384→          className={`border border-dashed rounded-xl p-8 text-center cursor-pointer transition-all duration-300 group ${
385→            isDragging
386→              ? "border-violet-400 bg-violet-500/10 scale-[1.02]"
387→              : "border-white/15 hover:border-violet-500/40 hover:bg-violet-500/5"
388→          }`}
389→        >
390→          <input
391→            ref={fileInputRef}
392→            type="file"
393→            accept=".csv,.txt"
394→            onChange={handleFileUpload}
395→            className="hidden"
396→          />
397→          {fileName ? (
398→            <div className="flex items-center justify-center gap-2 text-sm text-emerald-400">
399→              <CheckCircle2 className="w-5 h-5" />
400→              <span>{fileName}</span>
401→            </div>
402→          ) : isDragging ? (
403→            <div className="space-y-2">
404→              <Upload className="w-10 h-10 mx-auto text-violet-400 animate-bounce" />
405→              <p className="text-sm text-violet-300 font-medium">Drop your CSV file here</p>
406→            </div>
407→          ) : (
408→            <div className="space-y-2">
409→              <FileText className="w-10 h-10 mx-auto text-white/20 group-hover:text-violet-400/50 transition-colors" />
410→              <p className="text-sm text-white/30">Drag &amp; drop a CSV file here, or click to browse</p>
411→            </div>
412→          )}
413→        </div>
414→      </div>
415→
416→      <div>
417→        <label className="text-xs font-medium text-white/50 mb-1.5 block uppercase tracking-wider">
418→          Or Paste CSV Data
419→        </label>
420→        <Textarea
421→          placeholder={`rating,title,body,date,reviewer\n5,"Great product!","Love this...",2024-01-15,"John D."`}
422→          value={pastedCsv}
423→          onChange={(e) => {
424→            setPastedCsv(e.target.value);
425→            setCsvText(e.target.value);
426→            if (e.target.value.trim()) {
427→              setFileName("");
428→            }
429→          }}
430→          disabled={loading}
431→          className="font-mono text-xs bg-white/5 border-white/10 text-white/70 placeholder:text-white/15 focus:border-violet-500/50 focus:ring-violet-500/20 h-36 max-h-36 overflow-y-auto resize-none"
432→        />
433→        <p className="text-xs text-white/30 mt-1.5">
434→          Any CSV format accepted — columns are auto-detected from headers and content.
435→        </p>
436→      </div>
437→
438→      <button
439→        onClick={handleCsvSubmit}
440→        disabled={loading || !csvText.trim()}
441→        className="w-full gradient-btn text-white font-medium py-2.5 px-4 rounded-lg disabled:opacity-40 disabled:cursor-not-allowed flex items-center justify-center gap-2"
442→      >
443→        {loading ? (
444→          <>
445→            <Loader2 className="w-4 h-4 animate-spin" />
446→            Processing Reviews...
447→          </>
448→        ) : (
449→          <>
450→            <Upload className="w-4 h-4" />
451→            Upload &amp; Analyze
452→          </>
453→        )}
454→      </button>
455→    </>
456→  );
457→}
