  1→"use client";
  2→
  3→import { useState, useRef, useEffect, useCallback } from "react";
  4→import { Textarea } from "@/components/ui/textarea";
  5→import {
  6→  Send,
  7→  Loader2,
  8→  Shield,
  9→  ShieldAlert,
 10→  Bot,
 11→  User,
 12→  Sparkles,
 13→} from "lucide-react";
 14→import ReactMarkdown from "react-markdown";
 15→import { ChatMessage, ReviewMetadata } from "@/types";
 16→import { cn } from "@/lib/utils";
 17→
 18→interface ChatInterfaceProps {
 19→  sessionId: string;
 20→  metadata: ReviewMetadata;
 21→  compact?: boolean;
 22→}
 23→
 24→const SUGGESTED_QUESTIONS = [
 25→  "What are the most common complaints?",
 26→  "Summarize the positive reviews",
 27→  "What do customers say about quality?",
 28→  "Are there any recurring issues?",
 29→  "What features do reviewers mention most?",
 30→  "Compare 5-star vs 1-star review themes",
 31→];
 32→
 33→export default function ChatInterface({ sessionId, metadata, compact }: ChatInterfaceProps) {
 34→  const [messages, setMessages] = useState<ChatMessage[]>([]);
 35→  const [input, setInput] = useState("");
 36→  const [isStreaming, setIsStreaming] = useState(false);
 37→  const scrollContainerRef = useRef<HTMLDivElement>(null);
 38→  const messagesEndRef = useRef<HTMLDivElement>(null);
 39→  const textareaRef = useRef<HTMLTextAreaElement>(null);
 40→  const abortControllerRef = useRef<AbortController | null>(null);
 41→  const scrollToBottom = useCallback(() => {
 42→    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
 43→  }, []);
 44→
 45→  // Auto-scroll on every message update (including streaming chunks)
 46→  useEffect(() => {
 47→    scrollToBottom();
 48→  }, [messages, scrollToBottom]);
 49→
 50→  // Abort in-flight request on unmount
 51→  useEffect(() => {
 52→    return () => {
 53→      abortControllerRef.current?.abort();
 54→    };
 55→  }, []);
 56→
 57→  const sendMessage = async (messageText?: string) => {
 58→    const text = messageText || input.trim();
 59→    if (!text || isStreaming) return;
 60→
 61→    const userMessage: ChatMessage = {
 62→      id: crypto.randomUUID(),
 63→      role: "user",
 64→      content: text,
 65→      timestamp: new Date().toISOString(),
 66→    };
 67→
 68→    // Capture current messages for history BEFORE updating state
 69→    const currentMessages = [...messages];
 70→
 71→    setMessages((prev) => [...prev, userMessage]);
 72→    setInput("");
 73→    setIsStreaming(true);
 74→
 75→    const assistantId = crypto.randomUUID();
 76→    const assistantMessage: ChatMessage = {
 77→      id: assistantId,
 78→      role: "assistant",
 79→      content: "",
 80→      timestamp: new Date().toISOString(),
 81→    };
 82→    setMessages((prev) => [...prev, assistantMessage]);
 83→
 84→    try {
 85→      const history = currentMessages.map((m) => ({
 86→        role: m.role,
 87→        content: m.content,
 88→      }));
 89→
 90→      // Always send session data so the server can rehydrate if its
 91→      // in-memory store was cleared (deploy, worker recycle, TTL expiry)
 92→      let sessionData: Record<string, unknown> | undefined;
 93→      try {
 94→        const reviews = JSON.parse(sessionStorage.getItem("reviewlens_reviews") || "[]");
 95→        const meta = JSON.parse(sessionStorage.getItem("reviewlens_metadata") || "{}");
 96→        const analytics = JSON.parse(sessionStorage.getItem("reviewlens_analytics") || "{}");
 97→        if (reviews.length > 0) {
 98→          sessionData = { reviews, metadata: meta, analytics };
 99→        }
100→      } catch { /* proceed without */ }
101→
102→      // Abort any previous in-flight request
103→      abortControllerRef.current?.abort();
104→      const controller = new AbortController();
105→      abortControllerRef.current = controller;
106→
107→      const response = await fetch("/api/chat", {
108→        method: "POST",
109→        headers: {
110→          "Content-Type": "application/json",
111→          "Accept-Encoding": "identity",
112→          "Accept": "text/event-stream",
113→        },
114→        body: JSON.stringify({ sessionId, message: text, history, sessionData }),
115→        signal: controller.signal,
116→      });
117→
118→      if (!response.ok) throw new Error("Chat request failed");
119→
120→      const reader = response.body?.getReader();
121→      if (!reader) throw new Error("No response stream");
122→
123→      const decoder = new TextDecoder();
124→      let buffer = "";
125→
126→      for (;;) {
127→        const { done, value } = await reader.read();
128→        if (done) break;
129→
130→        buffer += decoder.decode(value, { stream: true });
131→
132→        let boundary = buffer.indexOf("\n\n");
133→        while (boundary !== -1) {
134→          const line = buffer.slice(0, boundary);
135→          buffer = buffer.slice(boundary + 2);
136→
137→          if (line.startsWith("data: ")) {
138→            try {
139→              const data = JSON.parse(line.slice(6));
140→              if (data.type === "text") {
141→                setMessages((prev) =>
142→                  prev.map((m) =>
143→                    m.id === assistantId ? { ...m, content: m.content + data.content } : m
144→                  )
145→                );
146→              } else if (data.type === "guard") {
147→                setMessages((prev) =>
148→                  prev.map((m) =>
149→                    m.id === assistantId
150→                      ? { ...m, content: data.content, scopeGuardTriggered: true, guardrailAction: data.action }
151→                      : m
152→                  )
153→                );
154→              } else if (data.type === "error") {
155→                setMessages((prev) =>
156→                  prev.map((m) =>
157→                    m.id === assistantId ? { ...m, content: data.content } : m
158→                  )
159→                );
160→              }
161→            } catch {
162→              /* skip invalid JSON */
163→            }
164→          }
165→
166→          boundary = buffer.indexOf("\n\n");
167→        }
168→      }
169→    } catch {
170→      setMessages((prev) =>
171→        prev.map((m) =>
172→          m.id === assistantId
173→            ? { ...m, content: "Sorry, something went wrong. Please try again." }
174→            : m
175→        )
176→      );
177→    } finally {
178→      setIsStreaming(false);
179→    }
180→  };
181→
182→  const handleKeyDown = (e: React.KeyboardEvent) => {
183→    if (e.key === "Enter" && !e.shiftKey) {
184→      e.preventDefault();
185→      sendMessage();
186→    }
187→  };
188→
189→  return (
190→    <div className={cn("flex flex-col", compact ? "h-full" : "h-[calc(100vh-10rem)]")}>
191→      {/* Chat header — hidden in compact/drawer mode */}
192→      {!compact && (
193→        <div className="glass-card rounded-xl px-4 py-3 mb-4 flex items-center gap-3">
194→          <div className="w-9 h-9 rounded-lg bg-linear-to-br from-emerald-500 to-green-600 flex items-center justify-center shadow-lg shadow-emerald-500/20">
195→            <Shield className="w-4 h-4 text-white" />
196→          </div>
197→          <div>
198→            <p className="text-sm font-semibold text-white/90">
199→              Guardrailed Q&A — {metadata.productName}
200→            </p>
201→            <p className="text-xs text-white/35">
202→              {metadata.totalReviews} {metadata.platform} reviews &middot; Dual-layer scope guard active
203→            </p>
204→          </div>
205→        </div>
206→      )}
207→
208→      {/* Messages area */}
209→      <div
210→        ref={scrollContainerRef}
211→        className="flex-1 min-h-0 overflow-y-auto pr-2 scrollbar-thin scrollbar-thumb-white/10 scrollbar-track-transparent"
212→      >
213→        <div className="space-y-4 pb-4">
214→          {messages.length === 0 && (
215→            <div className={cn("text-center animate-fade-in", compact ? "py-8" : "py-16")}>
216→              <div className={cn(
217→                "rounded-2xl bg-linear-to-br from-violet-500/20 to-indigo-500/20 flex items-center justify-center mx-auto border border-violet-500/10",
218→                compact ? "w-12 h-12 mb-3" : "w-16 h-16 mb-5"
219→              )}>
220→                <Bot className={cn(compact ? "w-6 h-6" : "w-8 h-8", "text-violet-400")} />
221→              </div>
222→              <h3 className={cn("font-semibold text-white/80 mb-2", compact ? "text-base" : "text-lg")}>
223→                Ask about the reviews
224→              </h3>
225→              <p className={cn("text-sm text-white/35 max-w-md mx-auto", compact ? "mb-5" : "mb-8")}>
226→                I can analyze the {metadata.totalReviews} ingested {metadata.platform} reviews for{" "}
227→                <strong className="text-white/60">{metadata.productName}</strong>. I&apos;m scoped exclusively to this data.
228→              </p>
229→              <div className={cn("flex flex-wrap gap-2 justify-center", compact ? "max-w-sm" : "max-w-lg", "mx-auto")}>
230→                {SUGGESTED_QUESTIONS.map((q) => (
231→                  <button
232→                    key={q}
233→                    onClick={() => sendMessage(q)}
234→                    className="text-xs px-3.5 py-2 rounded-full glass hover:bg-violet-500/10 hover:border-violet-500/20 transition-all duration-200 text-white/50 hover:text-violet-300"
235→                  >
236→                    <Sparkles className="w-3 h-3 inline mr-1.5 text-violet-400" />
237→                    {q}
238→                  </button>
239→                ))}
240→              </div>
241→            </div>
242→          )}
243→
