        </label>
        <Textarea
          placeholder={`rating,title,body,date,reviewer\n5,"Great product!","Love this...",2024-01-15,"John D."`}
          value={pastedCsv}
          onChange={(e) => {
            setPastedCsv(e.target.value);
            setCsvText(e.target.value);
            if (e.target.value.trim()) {
              setFileName("");
