      </>
    );
  }

  return (
    <>
      <Header />
      <main className="flex-1 max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        <ChatInterface sessionId={data.sessionId} metadata={data.metadata} />
